import{_ as a,c as e,o as l,ag as t}from"./chunks/framework.z0p7P-Mv.js";const c=JSON.parse('{"title":"HPA（Horizontal Pod Autoscaler）水平Pod自动伸缩","description":"","frontmatter":{},"headers":[],"relativePath":"zh/k8s/HPA.md","filePath":"zh/k8s/HPA.md"}'),r={name:"zh/k8s/HPA.md"};function i(d,o,p,s,n,u){return l(),e("div",null,[...o[0]||(o[0]=[t('<h1 id="hpa-horizontal-pod-autoscaler-水平pod自动伸缩" tabindex="-1">HPA（Horizontal Pod Autoscaler）水平Pod自动伸缩 <a class="header-anchor" href="#hpa-horizontal-pod-autoscaler-水平pod自动伸缩" aria-label="Permalink to &quot;HPA（Horizontal Pod Autoscaler）水平Pod自动伸缩&quot;">​</a></h1><h2 id="_1-1-pod伸缩简介" tabindex="-1">1.1 Pod伸缩简介 <a class="header-anchor" href="#_1-1-pod伸缩简介" aria-label="Permalink to &quot;1.1 Pod伸缩简介&quot;">​</a></h2><ul><li><p>根据当前pod的负载，动态调整pod副本数量，业务高峰期自动扩容pod的副本数以尽快响应pod的请求。</p></li><li><p>在业务低峰期对pod进行缩容，实现降本增效的目的。</p></li><li><p>公有云支持node级别的弹性伸缩。</p></li><li></li></ul><h2 id="_1-2-动态控制器类型" tabindex="-1">1.2 动态控制器类型 <a class="header-anchor" href="#_1-2-动态控制器类型" aria-label="Permalink to &quot;1.2 动态控制器类型&quot;">​</a></h2><ul><li>水平pod自动缩放器(HPA)： <ul><li>基于pod CPU及内存资源利用率或者使用值。</li><li>可扩展基于prometheus收集的其它自定义指标的当前值横向调整pod副本数量。</li></ul></li><li>垂直pod自动缩放器(VPA)： <ul><li>基于pod资源利用率或其它扩展自定义指标，调整对单个pod的最大资源限制</li><li>VPA不能与HPA同时使用。</li></ul></li><li>集群伸缩(Cluster Autoscaler,CA) <ul><li>基于集群中node 资源使用情况，动态伸缩node节点，从而保证有CPU和内存资源用于创建pod。</li><li><a href="https://github.com/kubernetes/autoscaler" target="_blank" rel="noreferrer">https://github.com/kubernetes/autoscaler</a></li></ul></li></ul><h2 id="_1-3-手动调整pod副本数" tabindex="-1">1.3 手动调整pod副本数 <a class="header-anchor" href="#_1-3-手动调整pod副本数" aria-label="Permalink to &quot;1.3 手动调整pod副本数&quot;">​</a></h2>',6)])])}const P=a(r,[["render",i]]);export{c as __pageData,P as default};
